#include <iostream>
#include <vector>
#include <algorithm>
#include <random>
#include <cmath>
#include <numeric>

// Define the structure for a single solution (Chromosome)
struct Chromosome {
    std::vector<double> genes; // The parameters we are optimizing

    // Constructor
    Chromosome(size_t gene_count) : genes(gene_count) {}

    // For easy printing/debugging
    void print() const {
        std::cout << "Genes: [";
        for (size_t i = 0; i < genes.size(); ++i) {
            std::cout << genes[i] << (i == genes.size() - 1 ? "" : ", ");
        }
        std::cout << "]" << std::endl;
    }
};

